let phone = $json["body.billing.phone"];
let id = $json["body.id"];

// Jodi phone number thake, tobe formatting logic kaj korbe
if (phone) {
  // Shob non-numeric character (space, dash) muche fela
  let cleanPhone = phone.toString().replace(/\D/g, '');

  // Logic: 0 diye shuru hole +880 add korbe
  if (cleanPhone.startsWith('0')) {
    cleanPhone = '+880' + cleanPhone.substring(1);
  } 
  // Jodi 880 diye shuru hoy kintu + nei
  else if (cleanPhone.startsWith('880')) {
    cleanPhone = '+' + cleanPhone;
  }
  // Jodi shudhu 1 die shuru hoy (e.g. 194...)
  else if (cleanPhone.startsWith('1') || cleanPhone.startsWith('1')) {
    cleanPhone = '+880' + cleanPhone;
  }

  // Final output
  return {
    formatted_phone: cleanPhone,
    order_id: id
  };
}

// Jodi phone na thake tobe default return
return {
  formatted_phone: null,
  order_id: id
};

