for (const item of items) {
  let text = item.json.output || "";

  if (typeof text === 'string') {
    // 1. Carriage return (\r) remove kora
    text = text.replace(/\r/g, "");

    // 2. Joto jaygay \n er pore dash (-) ba space thake, shegulo ke clean kora
    // Eta apnar screenshot-er \n\n- problem-ta solve korbe
    text = text.replace(/\n\s*[-]*\s*\n+/g, "\n");

    // 3. Ekhon double newline (\n\n) ke single newline (\n) kora
    text = text.replace(/\n+/g, "\n");

    // 4. Shuru ebong shesh-er faka jayga muche fela
    text = text.trim();

    // 5. WhatsApp-e pathanor jonno JSON escape kora
    // Logic: Prothome raw newline fix kora, tarpor escape kora
    item.json.output = text = text.replace(/\\n/g, "\n");
  }
}

return items;

