let phone = $json.body?.billing?.phone || $json.phone_number || $json.phone;
let id = $json.body?.id || $json.id;

// Jodi phone number thake
if (phone) {
  // Shob non-numeric character (+, space, dash) muche fela
  let cleanPhone = phone.toString().replace(/\D/g, '');

  // Case 1: Jodi 8801... diye shuru hoy (13 digits)
  if (cleanPhone.startsWith('880') && cleanPhone.length === 13) {
    // Already thik ache, kisu korar dorkar nai
  }
  // Case 2: Jodi 01... diye shuru hoy (11 digits)
  else if (cleanPhone.startsWith('0') && cleanPhone.length === 11) {
    cleanPhone = '88' + cleanPhone;
  }
  // Case 3: Jodi shudhu 1... diye shuru hoy (10 digits)
  else if (cleanPhone.startsWith('1') && cleanPhone.length === 10) {
    cleanPhone = '880' + cleanPhone;
  }
  // Case 4: Jodi bhule extra 88 thake (e.g., 888801...)
  else if (cleanPhone.length > 13 && cleanPhone.includes('880')) {
     cleanPhone = cleanPhone.substring(cleanPhone.indexOf('880'));
  }

  return {
    formatted_phone: cleanPhone,
    order_id: id
  };
}

// Phone na thakle null return korbe
return {
  formatted_phone: null,
  order_id: id
};

